<template>
  <nav class="navbar navbar-expand-lg navbar-dark">
    <div class="container">
      <router-link
        to="/"
        class="navbar-brand fw-bolder"
      >REZAHR</router-link>
      <button
        class="navbar-toggler"
        type="button"
        data-bs-toggle="collapse"
        data-bs-target="#navbarNav"
        aria-controls="navbarNav"
        aria-expanded="false"
        aria-label="Toggle navigation"
      >
        <span class="navbar-toggler-icon"></span>
      </button>
      <div
        class="collapse navbar-collapse"
        id="navbarNav"
      >
        <ul class="navbar-nav ms-auto">
          <li class="nav-item">
            <router-link
              to="/"
              class="nav-link"
              aria-current="page"
            >Home</router-link>
          </li>
          <li class="nav-item">
            <router-link
              to="/about"
              class="nav-link"
              aria-current="page"
            >About</router-link>
          </li>
          <li class="nav-item">
            <router-link
              to="/portfolio"
              class="nav-link"
              aria-current="page"
            >Portfolio</router-link>
          </li>
          <li class="nav-item">
            <router-link
              to="/contact-us"
              class="nav-link"
              aria-current="page"
            >Contac Us</router-link>
          </li>
        </ul>
      </div>
    </div>
  </nav>
</template>

<script>
export default {
  name: "NavBar",
  data() {
    return {};
  },
  created() {
    window.addEventListener("scroll", this.onScroll);
  },
  methods: {
    onScroll() {
      var scrollPos = window.pageYOffset;
      var navbar = document.querySelector(".navbar");

      if (scrollPos >= 10) {
        navbar.classList.add("position-fixed", "bg-blue");
      } else {
        navbar.classList.remove("position-fixed", "bg-blue");
      }
    },
  },
};
</script>

